// File structure becomes routing:
// app/page.tsx          -> /
// app/about/page.tsx    -> /about
// app/blog/[slug]/page.tsx -> /blog/<anything>

export default function HomePage() {
  return <h1>Welcome</h1>;
}

// app/about/page.tsx — reachable at /about
export default function AboutPage() {
  return (
    <main>
      <h1>About</h1>
      <p>This is the about page.</p>
    </main>
  );
}

// app/layout.tsx — wraps every page in the app
export default function RootLayout({ children }) {
  return (
    <html>
      <body>
        <header>My App</header>
        <main>{children}</main>
      </body>
    </html>
  );
}

// app/blog/[slug]/page.tsx — matches /blog/hello, /blog/world, /blog/anything
type Props = { params: Promise<{ slug: string }> };

export default async function BlogPost({ params }: Props) {
  const { slug } = await params;
  return <article>Post about: {slug}</article>;
}

